// src/pages/ProductDetails.js
import { useParams } from "react-router-dom";
import { useState } from "react";
import products from "../data/ProductData";

function ProductDetails() {
  const { id } = useParams();
  const product = products.find((p) => p.id === parseInt(id));

  if (!product)
    return <h2 className="text-center mt-10">Product Not Found</h2>;

  // handle multiple images (main + gallery)
  const images = [product.image, ...(product.images || [])];
  const [mainImage, setMainImage] = useState(images[0]);

  return (
    <div className="max-w-6xl mx-auto p-8 grid md:grid-cols-2 gap-10">
      {/* Left - Product Images */}
      <div className="flex flex-col items-center">
        {/* Main Image */}
        <div className="w-[150px] h-[350px] flex items-center justify-center border rounded-lg shadow">
          <img
            src={mainImage}
            alt={product.name}
            className="max-w-full max-h-full object-contain"
          />
        </div>

        {/* Thumbnails */}
        <div className="flex gap-2 mt-4">
          {images.map((img, idx) => (
            <img
              key={idx}
              src={img}
              alt={'${product.name} ${idx}'}
              className={`w-20 h-20 object-contain border rounded cursor-pointer ${
                mainImage === img ? "ring-2 ring-blue-500" : ""
              }`}
              onClick={() => setMainImage(img)}
            />
          ))}
        </div>
      </div>

      {/* Right - Product Details */}
      <div>
        <h1 className="text-3xl font-bold">{product.name}</h1>
        <p className="mt-4 text-gray-600">{product.description}</p>
        <p className="mt-4 text-2xl font-semibold">₹{product.price}</p>
      </div>
    </div>
  );
}

export default ProductDetails;
